2862 /// This function tries convert extended in-loop reductions to
2863 /// VPExpressionRecipe and clamp the \p Range if it is beneficial and
2864 /// valid. The created recipe must be decomposed to its constituent
2865 /// recipes before execution.
2866 static VPExpressionRecipe *
2867 tryToMatchAndCreateExtendedReduction(VPReductionRecipe *Red, VPCostContext &Ctx,
2868                                      VFRange &Range) {
2869   using namespace VPlanPatternMatch;
2870 
2871   Type *RedTy = Ctx.Types.inferScalarType(Red);
2872   VPValue *VecOp = Red->getVecOp();
2873 
2874   // Clamp the range if using extended-reduction is profitable.
2875   auto IsExtendedRedValidAndClampRange = [&](unsigned Opcode, bool isZExt,
2876                                              Type *SrcTy) -> bool {
2877     return LoopVectorizationPlanner::getDecisionAndClampRange(
2878         [&](ElementCount VF) {
2879           auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
2880           TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
2881           InstructionCost ExtRedCost = Ctx.TTI.getExtendedReductionCost(
2882               Opcode, isZExt, RedTy, SrcVecTy, Red->getFastMathFlags(),
2883               CostKind);
2884           InstructionCost ExtCost =
2885               cast<VPWidenCastRecipe>(VecOp)->computeCost(VF, Ctx);
2886           InstructionCost RedCost = Red->computeCost(VF, Ctx);
2887           return ExtRedCost.isValid() && ExtRedCost < ExtCost + RedCost;
2888         },
2889         Range);
2890   };
2891 
2892   VPValue *A;
2893   // Match reduce(ext)).
2894   if (match(VecOp, m_ZExtOrSExt(m_VPValue(A))) &&
2895       IsExtendedRedValidAndClampRange(
2896           RecurrenceDescriptor::getOpcode(Red->getRecurrenceKind()),
2897           cast<VPWidenCastRecipe>(VecOp)->getOpcode() ==
2898               Instruction::CastOps::ZExt,
2899           Ctx.Types.inferScalarType(A)))
2900     return new VPExpressionRecipe(cast<VPWidenCastRecipe>(VecOp), Red);
2901 
2902   return nullptr;
2903 }
