3013 /// This function tries to create abstract recipes from the reduction recipe for
3014 /// following optimizations and cost estimation.
3015 static void tryToCreateAbstractReductionRecipe(VPReductionRecipe *Red,
3016                                                VPCostContext &Ctx,
3017                                                VFRange &Range) {
3018   VPExpressionRecipe *AbstractR = nullptr;
3019   auto IP = std::next(Red->getIterator());
3020   auto *VPBB = Red->getParent();
3021   if (auto *MulAcc = tryToMatchAndCreateMulAccumulateReduction(Red, Ctx, Range))
3022     AbstractR = MulAcc;
3023   else if (auto *ExtRed = tryToMatchAndCreateExtendedReduction(Red, Ctx, Range))
3024     AbstractR = ExtRed;
3025   // Cannot create abstract inloop reduction recipes.
3026   if (!AbstractR)
3027     return;
3028 
3029   AbstractR->insertBefore(*VPBB, IP);
3030   Red->replaceAllUsesWith(AbstractR);
3031 }
