359                       m_VPValue(), m_VPValue(), m_VPValue(), m_VPValue(Op1)))) {
360       addUniformForAllParts(cast<VPInstruction>(&R));
361       for (unsigned Part = 1; Part != UF; ++Part)
362         R.addOperand(getValueForPart(Op1, Part));
363       continue;
364     }
365     VPValue *Op0;
366     if (match(&R, m_VPInstruction<VPInstruction::ExtractLane>(
367                       m_VPValue(Op0), m_VPValue(Op1)))) {
368       addUniformForAllParts(cast<VPInstruction>(&R));
369       for (unsigned Part = 1; Part != UF; ++Part)
370         R.addOperand(getValueForPart(Op1, Part));
371       continue;
372     }
373     if (match(&R, m_VPInstruction<VPInstruction::ExtractLastElement>(
374                       m_VPValue(Op0))) ||
375         match(&R, m_VPInstruction<VPInstruction::ExtractPenultimateElement>(
376                       m_VPValue(Op0)))) {
377       addUniformForAllParts(cast<VPSingleDefRecipe>(&R));
378       if (Plan.hasScalarVFOnly()) {
379         auto *I = cast<VPInstruction>(&R);
380         // Extracting from end with VF = 1 implies retrieving the last or
381         // penultimate scalar part (UF-1 or UF-2).
382         unsigned Offset =
383             I->getOpcode() == VPInstruction::ExtractLastElement ? 1 : 2;
384         I->replaceAllUsesWith(getValueForPart(Op0, UF - Offset));
385         R.eraseFromParent();
386       } else {
387         // Otherwise we extract from the last part.
388         remapOperands(&R, UF - 1);
389       }
390       continue;
391     }
392 
393     auto *SingleDef = dyn_cast<VPSingleDefRecipe>(&R);
394     if (SingleDef && vputils::isUniformAcrossVFsAndUFs(SingleDef)) {
395       addUniformForAllParts(SingleDef);
396       continue;
397     }
398 
399     if (auto *H = dyn_cast<VPHeaderPHIRecipe>(&R)) {
400       unrollHeaderPHIByUF(H, InsertPtForPhi);
401       continue;
402     }
403 
404     unrollRecipeByUF(R);
405   }
