501 void VPlanTransforms::replicateByVF(VPlan &Plan, ElementCount VF) {
502   Type *IdxTy = IntegerType::get(
503       Plan.getScalarHeader()->getIRBasicBlock()->getContext(), 32);
504 
505   // Visit all VPBBs outside the loop region and directly inside the top-level
506   // loop region.
507   auto VPBBsOutsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
508       vp_depth_first_shallow(Plan.getEntry()));
509   auto VPBBsInsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
510       vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()));
511   auto VPBBsToUnroll =
512       concat<VPBasicBlock *>(VPBBsOutsideLoopRegion, VPBBsInsideLoopRegion);
513   for (VPBasicBlock *VPBB : VPBBsToUnroll) {
514     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
515       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
516       if (!RepR || RepR->isSingleScalar())
517         continue;
518 
519       VPBuilder Builder(RepR);
520       if (RepR->getNumUsers() == 0) {
521         if (isa<StoreInst>(RepR->getUnderlyingInstr()) &&
522             vputils::isSingleScalar(RepR->getOperand(1))) {
523           // Stores to invariant addresses need to store the last lane only.
524           cloneForLane(Plan, Builder, IdxTy, RepR,
525                        VPLane::getLastLaneForVF(VF));
526         } else {
527           // Create single-scalar version of RepR for all lanes.
528           for (unsigned I = 0; I != VF.getKnownMinValue(); ++I)
529             cloneForLane(Plan, Builder, IdxTy, RepR, VPLane(I));
530         }
531         RepR->eraseFromParent();
532         continue;
533       }
534       /// Create single-scalar version of RepR for all lanes.
535       SmallVector<VPValue *> LaneDefs;
536       for (unsigned I = 0; I != VF.getKnownMinValue(); ++I)
537         LaneDefs.push_back(cloneForLane(Plan, Builder, IdxTy, RepR, VPLane(I)));
538 
539       /// Users that only demand the first lane can use the definition for lane
540       /// 0.
541       RepR->replaceUsesWithIf(LaneDefs[0], [RepR](VPUser &U, unsigned) {
542         return U.onlyFirstLaneUsed(RepR);
543       });
544 
545       // If needed, create a Build(Struct)Vector recipe to insert the scalar
546       // lane values into a vector.
547       Type *ResTy = RepR->getUnderlyingInstr()->getType();
548       VPValue *VecRes = Builder.createNaryOp(
549           ResTy->isStructTy() ? VPInstruction::BuildStructVector
550                               : VPInstruction::BuildVector,
551           LaneDefs);
552       RepR->replaceAllUsesWith(VecRes);
553       RepR->eraseFromParent();
554     }
555   }
556 }
